-- ---------------------------------------------------------------------------
-- 6K-2: Clear invalid flags on areatrigger_create_properties
-- 42 entries (35 unique IDs) with IsCustom=1 have non-zero flags
-- ---------------------------------------------------------------------------
UPDATE areatrigger_create_properties SET Flags = 0
WHERE IsCustom = 1 AND Id IN (
    1001,1002,1003,1004,1005,1006,1007,1008,1009,1010,1011,1012,1013,1014,
    1015,1016,1017,1018,1019,1020,1021,1022,1024,1026,1027,1028,1029,1035,
    1040,1041,1042,1048,1052,1053,1054
);

-- ---------------------------------------------------------------------------
-- 6E-1: Delete phase_area entries where the phase ID doesn't exist in DBC
-- 30 errors across 25 unique phase IDs
-- ---------------------------------------------------------------------------
DELETE FROM phase_area WHERE PhaseId IN (
    9007,9009,9014,9015,9016,9020,9021,9022,9031,9032,9035,9036,9037,
    19895,20180,20322,20338,20415,20425,20426,20427,20428,20434,21434,43558
);

-- ---------------------------------------------------------------------------
-- 6E-2: Delete phase_area entries where the area ID doesn't exist
-- 4 errors across 3 unique area IDs (0, 895, 1502)
-- ---------------------------------------------------------------------------
DELETE FROM phase_area WHERE AreaId IN (0, 895, 1502);

-- ---------------------------------------------------------------------------
-- 6E-3: Delete conditions for non-existent phase+area combinations
-- SourceTypeOrReferenceId=26 (Phase), SourceGroup=PhaseId, SourceEntry=AreaId
-- 261 conditions reference phases that don't apply to their areas.
-- Remove conditions that reference the already-deleted phase_area phases
-- ---------------------------------------------------------------------------
DELETE FROM conditions
WHERE SourceTypeOrReferenceId = 26
  AND SourceGroup IN (
    9007,9009,9014,9015,9016,9020,9021,9022,9031,9032,9035,9036,9037,
    19895,20180,20322,20338,20415,20425,20426,20427,20428,20434,21434,43558
);
